import{jsx as _jsx}from"react/jsx-runtime";import{usePlatform}from"../../hooks/usePlatform";import{Caption}from"../Typography/Caption/Caption";import{Footnote}from"../Typography/Footnote/Footnote";import{Text}from"../Typography/Text/Text";import{Title}from"../Typography/Title/Title";import styles from"./Alert.module.css";const AlertHeader=e=>{var t=usePlatform();return _jsx(Title,"ios"!==t?{className:styles.Alert__header,weight:"2",level:"2",...e}:{className:styles.Alert__header,weight:"1",level:"3",...e})},AlertText=e=>{switch(usePlatform()){case"vkcom":return _jsx(Footnote,{className:styles.Alert__text,...e});case"ios":return _jsx(Caption,{className:styles.Alert__text,...e});default:return _jsx(Text,{Component:"span",className:styles.Alert__text,weight:"3",...e})}};export{AlertHeader,AlertText};